class Solution:
    def minimumTotalDistance(self, robot, factory):
        robot = sorted(robot)
        fac = sorted(factory)
        m = len(robot)
        INF = float('inf')
        import sys
        sys.setrecursionlimit(100000)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def solve(i, j):
            if i == m:
                return 0
            if j == len(fac):
                return INF
            best = solve(i, j + 1)
            pos, lim = fac[j]
            cost = 0
            for t in range(1, lim + 1):
                if i + t - 1 >= m:
                    break
                cost += abs(robot[i + t - 1] - pos)
                sub = solve(i + t, j + 1)
                if sub != INF:
                    best = min(best, cost + sub)
            return best
        return solve(0, 0)

