class Solution:
    def minimumTotalDistance(self, robot, factory):
        robot.sort()
        factory.sort()
        m = len(robot)
        INF = float('inf')
        dp = [INF] * (m + 1)
        dp[0] = 0
        for pos, lim in factory:
            ndp = dp[:]
            for i in range(1, m + 1):
                cost = 0
                for t in range(1, min(lim, i) + 1):
                    cost += abs(robot[i - t] - pos)
                    if dp[i - t] != INF:
                        ndp[i] = min(ndp[i], dp[i - t] + cost)
            dp = ndp
        return dp[m]

