var minimumTotalDistance = function(robot, factory) {
    robot.sort((a, b) => a - b);
    factory.sort((a, b) => a[0] - b[0]);
    const m = robot.length;
    const INF = Infinity;
    let dp = new Array(m + 1).fill(INF);
    dp[0] = 0;
    for (const [pos, lim] of factory) {
        const ndp = dp.slice();
        for (let i = 1; i <= m; i++) {
            let cost = 0;
            const maxT = Math.min(lim, i);
            for (let t = 1; t <= maxT; t++) {
                cost += Math.abs(robot[i - t] - pos);
                if (dp[i - t] !== INF) {
                    ndp[i] = Math.min(ndp[i], dp[i - t] + cost);
                }
            }
        }
        dp = ndp;
    }
    return dp[m];
};
